#include<bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) meke_pair(x,y);
#define inf 0x3f3f3f3f
using namespace std;
inline ll read(){
    ll x=0,f=1;
    char ch=getchar();
    while(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
    while(ch>='0'&&ch<='9')x=x*10+ch-'0',ch=getchar();
    return x*f;
}
void write(ll x){
    if(x<0)putchar('-'),x=-x;
    if(x>9)write(x/10);
    putchar(x%10+'0');return;
}
CI MAXN=14,MAXM=1<<14;
int n,m,T[MAXM][305],len[MAXM];
ll f[MAXN][MAXM];
bool flag[MAXM];
bool check(int x)
{
    int cnt=0;
    for(int i=0;i<n;++i)
    {
        if(x>>i&1)
        {
            if(cnt&1)
            {
                return false;
            }
            cnt=0;
        }
        else
        {
            ++cnt;
        }
    }
    return (!(cnt&1));
}
int main(void)
{
    while(true)
    {
        cin>>n>>m;
        if(n==0&&m==0)break;
        //预处理
        for(int i=0;i<1<<n;++i)
        {
            flag[i]=check(i);
        }
        for(int i=0;i<1<<n;++i)
        {
            len[i]=0;
            for(int j=0;j<1<<n;++j)
            {
                if(!(i&j)&&flag[i|j])
                {
                    T[i][len[i]++]=j;
                }
            }
        }
        //计算状态
        memset(f,0,sizeof f);
        f[0][0]=1;
        for(int i=1;i<=m;++i)
        {
            for(int j=0;j<1<<n;++j)
            {
                for(int k=0;k<len[j];++k)
                {
                    f[i][j]+=f[i-1][T[j][k]];
                }
            }
        }
        write(f[m][0]);
        puts("");
    }
	return false;
}
